const cp = require('child_process');
const fs = require('fs');
const os = require('os');
const projRoot = '__PROJECT_ROOT__';

try {
  const scanResult = cp.execSync('bash scripts/scan-projects.sh 2>&1', {cwd: projRoot, timeout: 30000, encoding: 'utf8'});
  const driftResult = cp.execSync('bash scripts/check-drift.sh 2>&1', {cwd: projRoot, timeout: 30000, encoding: 'utf8'});
  const gitLog = cp.execSync('git log --oneline --since="24 hours ago" 2>/dev/null || echo "no commits"', {cwd: projRoot, timeout: 5000, encoding: 'utf8'});

  const prompt = 'Based on this data write a 5-line daily briefing. What needs attention, progress, blockers. Be direct.\n\nProject scan:\n' + scanResult + '\nDrift:\n' + driftResult + '\nCommits 24h:\n' + gitLog;

  // SAFE: write prompt to temp file, pass via stdin — no shell injection possible
  const tmpFile = os.tmpdir() + '/briefing-' + Date.now() + '.txt';
  fs.writeFileSync(tmpFile, prompt.substring(0, 4000));
  const briefing = cp.execSync('claude -p < "' + tmpFile.replace(/\/g, '/') + '"', {timeout: 120000, encoding: 'utf8', shell: true}).trim();
  try { fs.unlinkSync(tmpFile); } catch {}

  return [{json: {status: 'complete', briefing, timestamp: new Date().toISOString()}}];
} catch(e) {
  return [{json: {status: 'error', error: (e.stderr || '') + e.message}}];
}
